package keywords;

public class switch1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
int  j = 2;
		 switch(j) {
		 case 1 : System.out.println(" 1 is condition");
		 break;
		 
		 case 2 : System.out.println(" 2 is condition");
		 break;
		 
		 case 3 : System.out.println(" 3 is condition");
		 break;
		 
		  default :  System.out.println(" no  condition");
		 }
		 
	}

}
